import React, { useState } from 'react';
import BatchDashboard from './BatchDashboard';

function BatchProcessing() {
  const [uploadedFile, setUploadedFile] = useState(null);
  const [dashboardData, setDashboardData] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleFileUpload = async (event) => {
    const file = event.target.files[0];
    if (!file) return;

    setUploadedFile(file);
    setIsLoading(true);

    try {
      const formData = new FormData();
      formData.append('file', file);

      const response = await fetch('http://localhost:5000/api/batch/analyze', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error('Failed to analyze batch data');
      }

      const result = await response.json();
      setDashboardData(result);
    } catch (error) {
      console.error('Error analyzing batch data:', error);
      alert('Error analyzing batch data: ' + error.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="batch-processing">
      <div className="upload-section">
        <h3>Upload Customer Data CSV</h3>
        <input
          type="file"
          accept=".csv"
          onChange={handleFileUpload}
          id="batch-file-upload"
        />
        <label htmlFor="batch-file-upload" className="upload-btn">
          Choose CSV File
        </label>
        {uploadedFile && (
          <div className="file-info">
            Selected: {uploadedFile.name}
          </div>
        )}
      </div>

      {isLoading && <div className="loading">Analyzing data...</div>}

      {dashboardData && (
        <BatchDashboard 
          dashboardData={dashboardData} 
          uploadedFile={uploadedFile}
        />
      )}
    </div>
  );
}

export default BatchProcessing;
